import numpy as np

def matrixmul(a: list[list[int|float]], b: list[list[int|float]]) -> list[list[int|float]]:
    A = np.array(a)
    B = np.array(b)

    if A.ndim != 2 or B.ndim != 2 or A.shape[1] != B.shape[0]:
        return -1

    C = A @ B
    return C.tolist()

