import torch

def matrixmul(a: list[list[int|float]], b: list[list[int|float]]) -> list[list[int|float]]:
    A = torch.tensor(a, dtype=torch.float32)
    B = torch.tensor(b, dtype=torch.float32)

    if A.dim() != 2 or B.dim() != 2 or A.shape[1] != B.shape[0]:
        return -1

    C = torch.mm(A, B)
    return C.tolist()
